import React, { useState } from 'react';
import './App.css';

function App() {
  const [currentPage, setCurrentPage] = useState('welcome');
  const [role, setRole] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleRoleSelect = (selectedRole) => {
    setRole(selectedRole);
    setCurrentPage('register');
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const response = await fetch('http://localhost:8080/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          fullName: formData.name,
          email: formData.email,
          password: formData.password,
          role: role
        })
      });
      const data = await response.json();
      if (data.success) {
        setCurrentPage('login');
      } else {
        setError(data.error || 'Registration failed');
      }
    } catch (err) {
      setError('Connection error. Is the backend running?');
    } finally {
      setLoading(false);
    }
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await fetch('http://localhost:8080/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email: formData.email,
          password: formData.password
        })
      });
      const data = await response.json();
      if (data.success) {
        setCurrentPage('dashboard');
      } else {
        setError(data.error || 'Login failed');
      }
    } catch (err) {
      setError('Connection error. Is the backend running?');
    } finally {
      setLoading(false);
    }
  };

  if (currentPage === 'welcome') {
    return (
      <div className="container">
        <h1>Welcome to GlamSched</h1>
        <p>Register as:</p>
        <div className="role-cards">
          <div className="card" onClick={() => handleRoleSelect('CLIENT')}>
            <h3>Client</h3>
            <p>I want to book services</p>
          </div>
          <div className="card" onClick={() => handleRoleSelect('ARTIST')}>
            <h3>Artist</h3>
            <p>I want to offer services</p>
          </div>
        </div>
        <p>Already have an account? <button onClick={() => setCurrentPage('login')}>Login</button></p>
      </div>
    );
  }

  if (currentPage === 'register') {
    return (
      <div className="container">
        <h1>Create Account</h1>
        <p>Signing up as <strong>{role}</strong></p>
        <form onSubmit={handleRegister}>
          <input name="name" placeholder="Full Name" onChange={handleChange} required />
          <input name="email" type="email" placeholder="Email" onChange={handleChange} required />
          <input name="password" type="password" placeholder="Password" onChange={handleChange} required />
          <input name="confirmPassword" type="password" placeholder="Confirm Password" onChange={handleChange} required />
          {error && <p className="error">{error}</p>}
          <button type="submit" disabled={loading}>{loading ? 'Registering...' : 'Register'}</button>
        </form>
        <button className="back" onClick={() => setCurrentPage('welcome')}>Back</button>
      </div>
    );
  }

  if (currentPage === 'login') {
    return (
      <div className="container">
        <h1>Login</h1>
        <form onSubmit={handleLogin}>
          <input name="email" type="email" placeholder="Email" onChange={handleChange} required />
          <input name="password" type="password" placeholder="Password" onChange={handleChange} required />
          {error && <p className="error">{error}</p>}
          <button type="submit" disabled={loading}>{loading ? 'Logging in...' : 'Login'}</button>
        </form>
        <p>Don't have an account? <button onClick={() => setCurrentPage('welcome')}>Register</button></p>
      </div>
    );
  }

  if (currentPage === 'dashboard') {
    return (
      <div className="container">
        <h1>Dashboard</h1>
        <p>Welcome back! You are logged in.</p>
        <button onClick={() => setCurrentPage('welcome')}>Logout</button>
      </div>
    );
  }
}

export default App;
